```perl
#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use Text::CSV;

# Chemin vers le fichier PDF
my $pdf_file = 'mon_fichier.pdf';

# Ouvrir le PDF
my $pdf = PDF::API2->open($pdf_file);

# Extraire le texte de chaque page
my @pages = $pdf->pages;
my @texts = map { $pdf->page($_)->mediabox->page->extract_contents } @pages;

# Initialiser un CSV
my $csv = Text::CSV->new({ binary => 1, auto_diag => 1 });

# Stocker les informations extraites
my @info;
push @info, [ 'Page', 'Text' ] if $csv->combine(@info);

foreach my $page (0 .. $#texts) {
    my $text = $texts[$page];
    if ($text =~ /Author: (.+)/i) {
        my $author = $1;
        push @info, [ $page + 1, $author ];
    }
    if ($text =~ /Date: (.+)/i) {
        my $date = $1;
        push @info, [ $page + 1, $date ];
    }
}

# Écrire le CSV
open my $fh, '>', 'info.csv' or die "Can't open file: $!";
print $fh $csv->string, "\n";
close $fh;

print "Informations extraies et enregistrées dans info.csv\n";
```

Ce script lit le PDF, extrait le texte de chaque page, et cherche les chaînes "Author:" et "Date:" pour extraire l'auteur et la date du document. Les informations sont ensuite écrites dans un fichier CSV.

N'oublie pas d'installer les modules si ce n'est pas fait :

```bash
cpanm PDF::API2 Text::CSV
```

